    SET @MSJ = NULL;
    SET @MSJ2 = NULL;

    SELECT COUNT(*) INTO cSucursal 
    FROM sucursal 
    WHERE id = P_ID AND estado_registro = 1;

    IF cSucursal <= 0 THEN
