    ELSE
        UPDATE sucursal 
        SET estado = 0, usuario = P_USUARIO,
            estado_proceso = 'MODIFICADO'
        WHERE id = P_ID AND estado_registro = 1;

        SET @MSJ = 'Se dio de baja correctamente la sucursal';
    END IF;
END $$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE SP_ELIMINAR_SUCURSAL(
